#!/usr/bin/env node
/**
 * gen-whatsnew.mjs
 *
 * Generates src/components/dialogs/whatsNew.generated.ts from the top (latest)
 * section of CHANGELOG.md so the in-app "What's New" modal always reflects the
 * current release instead of a hand-maintained, drift-prone array.
 *
 * Freshness guard: the latest CHANGELOG section MUST reference the current
 * package.json version (e.g. `v0.13.6`); otherwise generation/--check fails so a
 * release cannot ship a stale modal.
 *
 * Usage:
 *   node scripts/gen-whatsnew.mjs           # write the generated file
 *   node scripts/gen-whatsnew.mjs --check   # exit 1 if the file is stale (CI/sync)
 */
import { readFileSync, writeFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const CHANGELOG = resolve(ROOT, "CHANGELOG.md");
const PKG = resolve(ROOT, "package.json");
const OUT = resolve(ROOT, "src/components/dialogs/whatsNew.generated.ts");

const MAX_ITEMS = 8;
const MAX_DETAIL = 240;

function build() {
  const version = JSON.parse(readFileSync(PKG, "utf-8")).version;
  const lines = readFileSync(CHANGELOG, "utf-8").split("\n");

  const start = lines.findIndex((l) => l.startsWith("## "));
  if (start < 0) throw new Error("[gen-whatsnew] No '## ' section found in CHANGELOG.md");
  let end = lines.length;
  for (let i = start + 1; i < lines.length; i++) {
    if (lines[i].startsWith("## ")) {
      end = i;
      break;
    }
  }
  const section = lines.slice(start, end);

  // Freshness guard: the latest section must reference the current version.
  if (!section.join("\n").includes(`v${version}`)) {
    throw new Error(
      `[gen-whatsnew] CHANGELOG.md's latest section does not mention current version v${version}. ` +
        "Add a CHANGELOG entry for this release before building.",
    );
  }

  const items = [];
  let category = "";
  for (const raw of section) {
    const h = raw.match(/^###\s+(.+)$/);
    if (h) {
      category = h[1].trim();
      continue;
    }
    const b = raw.match(/^-\s+(.+)$/);
    if (!b) continue;
    let text = b[1].trim();
    text = text.replace(/^v\d[\w.]*:\s*/, ""); // strip "vX.Y.Z:" prefix
    text = text.replace(/\s*\([^()]*`[^()]*\)\s*$/, ""); // strip trailing "(`files…`)"
    text = text.trim();
    if (!text) continue;
    if (text.length > MAX_DETAIL) text = `${text.slice(0, MAX_DETAIL - 1).trimEnd()}…`;
    items.push({ label: category || "Update", detail: text });
    if (items.length >= MAX_ITEMS) break;
  }
  if (items.length === 0) {
    throw new Error("[gen-whatsnew] No changelog bullets parsed from the latest section.");
  }
  return { version, items };
}

function render({ version, items }) {
  const body = items
    .map((it) => `  { label: ${JSON.stringify(it.label)}, detail: ${JSON.stringify(it.detail)} },`)
    .join("\n");
  return (
    "// AUTO-GENERATED by scripts/gen-whatsnew.mjs from CHANGELOG.md. Do not edit by hand.\n" +
    "// Run `pnpm gen:whatsnew` after updating CHANGELOG.md.\n" +
    "export interface WhatsNewItem {\n  label: string;\n  detail: string;\n}\n\n" +
    `export const WHATS_NEW_VERSION = ${JSON.stringify(version)};\n\n` +
    `export const WHATS_NEW_ITEMS: WhatsNewItem[] = [\n${body}\n];\n`
  );
}

const rendered = render(build());

if (process.argv.includes("--check")) {
  let current = "";
  try {
    current = readFileSync(OUT, "utf-8");
  } catch {
    // missing file => stale
  }
  if (current !== rendered) {
    console.error(
      "[gen-whatsnew] drift: src/components/dialogs/whatsNew.generated.ts is stale. Run `pnpm gen:whatsnew`.",
    );
    process.exit(1);
  }
  console.log("[gen-whatsnew] up to date");
} else {
  writeFileSync(OUT, rendered, "utf-8");
  console.log(`[gen-whatsnew] wrote ${OUT}`);
}
